<template><div class="layout-root"><header class="topbar"><div class="title-container"><img src="/img/logo.png" alt="logo" class="header-logo"><h1>Qiongjing Cosmora</h1></div><el-menu class="top-menu" mode="horizontal" :default-active="activeMenu" router><el-menu-item index="/app/full-chain"><span slot="title">Learn Loop</span></el-menu-item><el-menu-item index="/app/learning-path"><span slot="title">Learn Path</span></el-menu-item><el-menu-item index="/app/knowledge-quiz"><span slot="title">Quiz</span></el-menu-item><el-menu-item index="/app/ai-tutor"><span slot="title">AI Tutor</span></el-menu-item><el-menu-item index="/app/ai-doc"><span slot="title">Read</span></el-menu-item><el-menu-item index="/app/ai-media"><span slot="title">Generate</span></el-menu-item></el-menu><div class="header-right"><div class="user-info"><span class="user-dropdown-link"><span class="user-name">{{userName}}</span><el-avatar :size="40" :src="userAvatar"></el-avatar></span><button class="header-action-btn" @click="goProfile">Profile</button><button class="header-action-btn danger" @click="logout">Logout</button></div></div></header><main class="content"><router-view class="page-view"></router-view></main></div></template><script>import axios from 'axios';export default{name:'App',created(){const u=JSON.parse(localStorage.getItem('user'));if(u){this.userName=u.username||u.userId;this.userAvatar=u.avatar||'/yu-avatar.png';window.addEventListener('cosmora-user-updated',()=>{const u2=JSON.parse(localStorage.getItem('user'));if(u2){this.userName=u2.username||u2.userId;this.userAvatar=u2.avatar||'/yu-avatar.png'}})}},data(){return{userName:'',userAvatar:'/yu-avatar.png'}},computed:{activeMenu(){return this.$route.path}},methods:{goProfile(){this.$router.push({name:'Profile'})},logout(){localStorage.removeItem('user');this.$router.push('/login')}}}</script><style scoped>.layout-root{display:flex;flex-direction:column;height:100vh}.topbar{height:72px;background:#0d1117;border-bottom:1px solid #30363d;color:#c9d1d9;padding:0 24px;display:flex;align-items:center;gap:24px;box-shadow:0 1px 3px rgba(0,0,0,.3);position:sticky;top:0;z-index:999}.topbar h1{font-size:1.25rem;font-weight:600;margin:0;white-space:nowrap;color:#e6edf3}.top-menu{flex:1;height:72px;border-bottom:0!important;background:transparent!important}.top-menu.el-menu--horizontal{background:rgba(255,255,255,.06)!important;backdrop-filter:blur(16px);-webkit-backdrop-filter:blur(16px);border:1px solid rgba(255,255,255,.1)!important;border-radius:16px;height:48px;line-height:48px;display:flex;align-items:center;padding:0 6px}.top-menu.el-menu--horizontal>.el-menu-item{height:36px;line-height:36px;border-bottom:0!important;padding:0 16px;border-radius:10px;margin:0 2px;font-size:13px;font-weight:500;color:rgba(255,255,255,.65)!important}.top-menu.el-menu--horizontal>.el-menu-item:hover{background:rgba(255,255,255,.1)!important;color:#fff!important}.top-menu.el-menu--horizontal>.el-menu-item.is-active{background:rgba(255,255,255,.15)!important;color:#fff!important;font-weight:600}.content{flex:1;width:100%;height:100%;background:#0d1117;overflow-y:auto;overflow-x:hidden;min-width:0}.header-right{display:flex;align-items:center;gap:12px;margin-left:auto}.user-info{display:flex;align-items:center;gap:10px}.user-name{font-size:14px;font-weight:500;color:#c9d1d9}.header-action-btn{padding:6px 14px;border:1px solid #30363d;border-radius:6px;background:transparent;color:#c9d1d9;cursor:pointer;font-size:13px}.header-action-btn:hover{border-color:#58a6ff;color:#58a6ff}.header-action-btn.danger:hover{border-color:#f85149;color:#f85149}</style>